import React, { useState, useEffect } from 'react';
import {
  Container, Grid, Card, CardMedia, CardContent, 
  Typography, Button, TextField, Box, Chip
} from '@mui/material';
import axios from 'axios';

const categories = [
  { value: 'books', label: '📚 كتب' },
  { value: 'notes', label: '📝 ملازم' },
  { value: 'tools', label: '🔧 أدوات' },
  { value: 'electronics', label: '💻 إلكترونيات' },
  { value: 'other', label: '📦 أخرى' }
];

export default function Home() {
  const [products, setProducts] = useState([]);
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('');

  useEffect(() => {
    fetchProducts();
  }, [search, category]);

  const fetchProducts = async () => {
    const params = new URLSearchParams();
    if (search) params.append('search', search);
    if (category) params.append('category', category);

    const res = await axios.get(`http://localhost:5000/api/products?${params}`);
    setProducts(res.data);
  };

  return (
    <Container sx={{ py: 4 }}>
      <Typography variant="h4" gutterBottom align="center" color="primary">
        🎓 سوق الطلاب
      </Typography>

      {/* البحث والتصفية */}
      <Box sx={{ display: 'flex', gap: 2, mb: 4, flexWrap: 'wrap' }}>
        <TextField
          label="ابحث عن منتج..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          sx={{ flex: 1, minWidth: 200 }}
        />
        <Box sx={{ display: 'flex', gap: 1 }}>
          {categories.map(cat => (
            <Chip
              key={cat.value}
              label={cat.label}
              onClick={() => setCategory(category === cat.value ? '' : cat.value)}
              color={category === cat.value ? 'primary' : 'default'}
              clickable
            />
          ))}
        </Box>
      </Box>

      {/* شبكة المنتجات */}
      <Grid container spacing={3}>
        {products.map(product => (
          <Grid item xs={12} sm={6} md={4} key={product._id}>
            <Card sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
              <CardMedia
                component="img"
                height="200"
                image={product.images[0] || 'https://via.placeholder.com/300x200?text=No+Image'}
                alt={product.title}
              />
              <CardContent sx={{ flexGrow: 1 }}>
                <Typography variant="h6" noWrap>{product.title}</Typography>
                <Typography color="text.secondary" sx={{ mb: 1 }}>
                  {product.university} | {product.condition === 'new' ? 'جديد' : 'مستعمل'}
                </Typography>
                <Typography variant="h5" color="primary" sx={{ fontWeight: 'bold' }}>
                  {product.price} ر.س
                </Typography>
                <Typography variant="body2" sx={{ mt: 1 }}>
                  البائع: {product.seller?.name}
                </Typography>
                <Button 
                  variant="contained" 
                  fullWidth 
                  sx={{ mt: 2 }}
                  href={`tel:${product.seller?.phone}`}
                >
                  📞 تواصل مع البائع
                </Button>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
}
